const body = $input.first().json;
const showName = (body['Show Name'] || body.show_name || '').trim();
const episodeId = (body['Episode ID'] || body.episode_id || '').trim();
const ep_folder = showName.toLowerCase().replace(/[^a-z0-9]+/g, '_') + '_' + episodeId.toLowerCase();
const trackRaw = body['Track Modes'] || body.track_modes || 'standard';
const track_modes = typeof trackRaw === 'string' ? trackRaw.split(',').map(s => s.trim()).filter(Boolean) : trackRaw;
const autoCastRaw = body['Auto Accept Cast'] || body.auto_cast;
const auto_cast = autoCastRaw === 'true' || autoCastRaw === true;
return [{ json: { show_name: showName, episode_id: episodeId, ep_folder, raw_file_name: (body['Raw File Name'] || body.raw_file_name || '').trim(), source_lang: body['Source Language'] || body.source_lang || 'ja', track_modes, auto_cast } }];

const BASE = 'http://host.docker.internal:3000';
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
const ctx = $input.first().json;
const { ep_folder, raw_file_name, source_lang } = ctx;

await this.helpers.httpRequest({ method: 'POST', url: `${BASE}/api/isolate`, body: { ep_folder, raw_file_name, source_lang }, json: true });

for (let i = 0; i < 240; i++) {
  await sleep(30000);
  const s = await this.helpers.httpRequest({ method: 'GET', url: `${BASE}/api/isolate-status?ep_folder=${ep_folder}`, json: true });
  if (s.status === 'done') return [{ json: ctx }];
  if (s.status === 'error') throw new Error(`Isolate failed: ${s.message || 'unknown'}`);
}
throw new Error('Isolate timed out after 240 polls (2 hours)');

const BASE = 'http://host.docker.internal:3000';
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
const ctx = $input.first().json;

await this.helpers.httpRequest({ method: 'POST', url: `${BASE}/api/transcribe`, body: { ep_folder: ctx.ep_folder, source_lang: ctx.source_lang }, json: true });

for (let i = 0; i < 240; i++) {
  await sleep(30000);
  const s = await this.helpers.httpRequest({ method: 'GET', url: `${BASE}/api/transcribe-status?ep_folder=${ctx.ep_folder}`, json: true });
  if (s.status === 'done') return [{ json: ctx }];
  if (s.status === 'error') throw new Error(`Transcribe failed: ${s.message || 'unknown'}`);
}
throw new Error('Transcribe timed out after 240 polls (2 hours)');

const BASE = 'http://host.docker.internal:3000';
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
const ctx = $input.first().json;

// Segment lines
await this.helpers.httpRequest({ method: 'POST', url: `${BASE}/api/segment-lines`, body: { ep_folder: ctx.ep_folder }, json: true });
for (let i = 0; i < 120; i++) {
  await sleep(30000);
  const s = await this.helpers.httpRequest({ method: 'GET', url: `${BASE}/api/segment-status?ep_folder=${ctx.ep_folder}`, json: true });
  if (s.status === 'done') break;
  if (s.status === 'error') throw new Error(`Segment-lines failed: ${s.message || 'unknown'}`);
  if (i === 119) throw new Error('Segment-lines timed out after 60 minutes');
}

// Harvest voice seeds
await this.helpers.httpRequest({ method: 'POST', url: `${BASE}/api/harvest-seeds`, body: { ep_folder: ctx.ep_folder, show_name: ctx.show_name }, json: true });
for (let i = 0; i < 120; i++) {
  await sleep(30000);
  const g = await this.helpers.httpRequest({ method: 'GET', url: `${BASE}/api/gpu-status`, json: true });
  if (!g.locked) break;
  if (i === 119) throw new Error('Harvest-seeds timed out after 60 minutes');
}

// Cast review gate (skip if auto_cast)
if (!ctx.auto_cast) {
  for (let i = 0; i < 480; i++) {
    await sleep(30000);
    const c = await this.helpers.httpRequest({ method: 'GET', url: `${BASE}/api/cast-status?ep_folder=${ctx.ep_folder}`, json: true });
    if (c.cast_locked) break;
    if (i === 479) throw new Error('Cast review timed out after 4 hours — save the cast in the Yanflix UI to continue');
  }
}

return [{ json: ctx }];

const BASE = 'http://host.docker.internal:3000';
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
const ctx = $input.first().json;
const track_modes = ctx.track_modes || ['standard'];
const outputs = [];

for (const track_mode of track_modes) {
  // Generate audio (sync — waits for completion)
  await this.helpers.httpRequest({ method: 'POST', url: `${BASE}/api/generate-audio`, body: { ep_folder: ctx.ep_folder, track_mode }, json: true });

  // Fit audio (async) — poll GPU lock until released
  await this.helpers.httpRequest({ method: 'POST', url: `${BASE}/api/fit-audio`, body: { ep_folder: ctx.ep_folder, track_mode }, json: true });
  for (let i = 0; i < 240; i++) {
    await sleep(30000);
    const g = await this.helpers.httpRequest({ method: 'GET', url: `${BASE}/api/gpu-status`, json: true });
    if (!g.locked) break;
    if (i === 239) throw new Error(`Fit-audio timed out for track: ${track_mode}`);
  }

  // Render (sync — waits for completion)
  const r = await this.helpers.httpRequest({ method: 'POST', url: `${BASE}/api/render-video`, body: { ep_folder: ctx.ep_folder, track_mode }, json: true });
  outputs.push({ track_mode, output_path: r.output_path || `workspace/5_outputs/${ctx.ep_folder}_${track_mode}.mp4` });
}

return [{ json: { ...ctx, outputs, message: `Autopilot complete! ${outputs.length} track(s) rendered in workspace/5_outputs/` } }];
